      out.write("	 		<div class=\"swiper-wrapper\">\r\n");
      out.write("				<!-- ajax를 이용해서 swiper-slide를 append 해준다. -->\r\n");
      out.write("			</div>	\r\n");
      out.write("		</div>\r\n");
      out.write("		<div class=\"popup-row\">\r\n");
      out.write("			<label class=\"today-done-label\">\r\n");
      out.write("          		<input type=\"checkbox\" id=\"today-done-checkbox\" />\r\n");
      out.write("          		<span class=\"today-done-text\">오늘은 더 이상 보지않기</span>\r\n");
      out.write("        	</label>\r\n");
      out.write("			<div>\r\n");
      out.write("				<button id=\"popup-close-btn\">닫기</button>\r\n");
      out.write("			</div>\r\n");
      out.write("		</div>	\r\n");
      out.write("	</div> \r\n");
      out.write("	\r\n");
      out.write("	</body>\r\n");
      out.write("	<script>\r\n");
      out.write("		var popup = document.querySelector(\"#popup\");\r\n");
      out.write("		var todayIsDone = document.querySelector(\"#today-done-checkbox\");\r\n");
      out.write("		var closeBtn = document.querySelector(\"#popup-close-btn\");\r\n");
      out.write("		var popupCookieKey = \"today-done\";\r\n");
      out.write("		\r\n");
      out.write("		$.ajax({\r\n");
      out.write("			url: \"/IdolProject/event_popup_items.do\",\r\n");
      out.write("			method: \"GET\",\r\n");
      out.write("			dataType: \"json\",\r\n");
      out.write("			success (response) {\r\n");
      out.write("				// response 는 배열이다. [{image, bid, no}, ...]\r\n");
      out.write("				var swiperWrapper = document.querySelector(\".popupSwiper .swiper-wrapper\")\r\n");
      out.write("				\r\n");
      out.write("				for (var i = 0; i < response.length; i++) {\r\n");
      out.write("					var item = response[i];\r\n");
      out.write("					\r\n");
      out.write("					var swiperSlide = document.createElement(\"div\");\r\n");
      out.write("					swiperSlide.className = \"swiper-slide\";\r\n");
      out.write("					\r\n");
      out.write("					var swiperSlidePopupWrap = document.createElement(\"div\");\r\n");
      out.write("					swiperSlidePopupWrap.className = \"swiper-slide-popup-wrap\";\r\n");
      out.write("					\r\n");
      out.write("					var anchor = document.createElement(\"a\");\r\n");
      out.write("					anchor.href = \"");
      out.print(request.getContextPath());
      out.write("/event_cont.do?category_id=1&board_id=\"+ item.bid +\"&no=\" + item.no\r\n");
      out.write("				\r\n");
      out.write("					var img = document.createElement(\"img\");\r\n");
      out.write("					img.src = \"./resources/upload/notice/\" + item.image\r\n");
      out.write("					\r\n");
      out.write("					anchor.appendChild(img)\r\n");
      out.write("					swiperSlidePopupWrap.appendChild(anchor)\r\n");
      out.write("					swiperSlide.appendChild(swiperSlidePopupWrap)\r\n");
      out.write("					swiperWrapper.appendChild(swiperSlide)\r\n");
      out.write("				}\r\n");
      out.write("				\r\n");
      out.write("				const popupSwiper = new Swiper(\".popupSwiper\", {\r\n");
      out.write("				    loop: true,\r\n");
      out.write("				    autoplay: {\r\n");
      out.write("				      delay: 3000,\r\n");
      out.write("				    },\r\n");
      out.write("				  });\r\n");
      out.write("				\r\n");
      out.write("			},\r\n");
      out.write("			error(err) {\r\n");
      out.write("				console.log(err)\r\n");
      out.write("			}\r\n");
      out.write("		})\r\n");
      out.write("		\r\n");
      out.write("		\r\n");
      out.write("\r\n");
      out.write("		closeBtn.addEventListener(\"click\", function(){\r\n");
      out.write("			close();\r\n");
      out.write("		});\r\n");
      out.write("		\r\n");
      out.write("		function close(){\r\n");
      out.write("			if(todayIsDone.checked){\r\n");
      out.write("				//오늘은 더 이상 보지 않는 로직\r\n");
      out.write("				setCookie(popupCookieKey,todayIsDone.checked,1);\r\n");
